package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.DmfapplBasisBijdrage;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.criteria.Criterium;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
