public class CachedDmfapplBasisBijdrageService implements CachedService, DmfapplBasisBijdrageService {

    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;

    private static final ThreadLocal<CachedDmfapplBasisBijdrageBuffer> BUFFER = new ThreadLocal<>();

    @Autowired
    public CachedDmfapplBasisBijdrageService(DmfapplBasisBijdrageService dmfapplBasisBijdrageService) {
        super();
        this.dmfapplBasisBijdrageService = dmfapplBasisBijdrageService;
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public List<DmfapplBasisBijdrage> findByWerkgeversCategorieWerknemersKengetalLooncode(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetal, Integer looncode, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedWerknemersKengetalBijdrageService.findByWerkgeversCategorieWerknemersKengetalLooncode");
        CachedDmfapplBasisBijdrageBuffer buffer = CachedDmfapplBasisBijdrageService.getBuffer();
        DmfapplBasisBijdrageKey key = DmfapplBasisBijdrageKey.getStandardKey(werkgeversCategorie, werknemersKengetal, looncode);
        List<DmfapplBasisBijdrage> lijst = buffer.get(key);
        List<DmfapplBasisBijdrage> result = new ArrayList<>();
        if (lijst == null) {
            lijst = findByWerkgeversCategorieWerknemersKengetalLooncode(werkgeversCategorie, werknemersKengetal, looncode);
            buffer.put(key, lijst);
        }

        for (DmfapplBasisBijdrage werknemersKengetalBijdrage : lijst) {
            LocalDateInterval periode = new LocalDateInterval(werknemersKengetalBijdrage.getBeginDatum(), werknemersKengetalBijdrage.getEindDatum());
            if (periode.contains(datum)) {
                result.add(werknemersKengetalBijdrage);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public List<DmfapplBasisBijdrage> findByWerkgeversCategorieWerknemersKengetalWerknemersKengetalBijdrage(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetal, DmfapplWnkengetal werknemersKengetalBijdrage, LocalDate datum) {
        TimeLogContext.getInstance()
                .startTimeLogging("CachedWerknemersKengetalBijdrageService.findByWerkgeversCategorieWerknemersKengetalLooncodeWerkemersKengetalBijdrage");
        CachedDmfapplBasisBijdrageBuffer buffer = CachedDmfapplBasisBijdrageService.getBuffer();
        DmfapplBasisBijdrageKey key = DmfapplBasisBijdrageKey.getStandardKey(werkgeversCategorie, werknemersKengetal, werknemersKengetalBijdrage);
        List<DmfapplBasisBijdrage> lijst = buffer.get(key);
        List<DmfapplBasisBijdrage> result = new ArrayList<>();
        if (lijst == null) {
            lijst = findByWerkgeversCategorieWerknemersKengetalLooncodeWerkemersKengetalBijdrage(werkgeversCategorie, werknemersKengetal,
                    werknemersKengetalBijdrage);
            buffer.put(key, lijst);
        }

        for (DmfapplBasisBijdrage werknemersKengetalBijdrageRelatie : lijst) {
            LocalDateInterval periode =
                    new LocalDateInterval(werknemersKengetalBijdrageRelatie.getBeginDatum(), werknemersKengetalBijdrageRelatie.getEindDatum());
            if (periode.contains(datum)) {
                result.add(werknemersKengetalBijdrageRelatie);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }


    @Override
    public Boolean isOnderworpenAanRSZ(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Integer looncode,
            LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedWerknemersKengetalBijdrageService.isOnderworpenAanRsz");
        CachedDmfapplBasisBijdrageBuffer buffer = CachedDmfapplBasisBijdrageService.getBuffer();
        DmfapplBasisBijdrageKey key = DmfapplBasisBijdrageKey.getOnderworpenAanRSZKey(werkgeversCategorie, werknemersKengetal, looncode, datum);
        Boolean result = buffer.getIsOnderworpen(key);
        if (result == null) {
            result = dmfapplBasisBijdrageService.isOnderworpenAanRSZ(werkgeversCategorie, werknemersKengetal, looncode, datum);
            buffer.putIsOnderworpen(key, result);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public List<DmfapplBasisBijdrage> findWerknemersKengetalBijdragesByWgCategorieWnKengetal(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedWerknemersKengetalBijdrageService.findwerknemersKengetalBijdragesByWgCategorieWnKengetal");
        CachedDmfapplBasisBijdrageBuffer buffer = CachedDmfapplBasisBijdrageService.getBuffer();
        DmfapplBasisBijdrageKey key = DmfapplBasisBijdrageKey.getFietsleaseFaktorKey(werkgeversCategorie, werknemersKengetal, datum);
        List<DmfapplBasisBijdrage> list = buffer.get(key);
        List<DmfapplBasisBijdrage> result = new ArrayList<>();
        if (list == null) {
            list = dmfapplBasisBijdrageService.findWerknemersKengetalBijdragesByWgCategorieWnKengetal(werkgeversCategorie, werknemersKengetal, datum);
            buffer.put(key, list);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public List<DmfapplBasisBijdrage> findStandaardBasisBijdragenGewoonLoon(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedWerknemersKengetalBijdrageService.findwerknemersKengetalBijdragesByWgCategorieWnKengetal");
        CachedDmfapplBasisBijdrageBuffer buffer = CachedDmfapplBasisBijdrageService.getBuffer();
        DmfapplBasisBijdrageKey key = DmfapplBasisBijdrageKey.getStandardGewoonLoonKey(werkgeversCategorie, werknemersKengetal, datum);
        List<DmfapplBasisBijdrage> list = buffer.get(key);
        List<DmfapplBasisBijdrage> result = new ArrayList<>();
        if (list == null) {
            list = dmfapplBasisBijdrageService.findStandaardBasisBijdragenGewoonLoon(werkgeversCategorie, werknemersKengetal, datum);
            buffer.put(key, list);
        }
        for (DmfapplBasisBijdrage werknemersKengetalBijdrageRelatie : list) {
            LocalDateInterval periode =
                    new LocalDateInterval(werknemersKengetalBijdrageRelatie.getBeginDatum(), werknemersKengetalBijdrageRelatie.getEindDatum());
            if (periode.contains(datum)) {
                result.add(werknemersKengetalBijdrageRelatie);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private List<DmfapplBasisBijdrage> findByWerkgeversCategorieWerknemersKengetalLooncode(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetal, Integer looncode) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("werkgeversCategorieCtId", Criterium.EQ(werkgeversCategorie.getId()));
        cb.and("werknemersKengetalCtId", Criterium.EQ(werknemersKengetal.getId()));
        cb.and("looncode", Criterium.EQ(looncode));
        return dmfapplBasisBijdrageService.findByCriteria(cb);
    }

    private List<DmfapplBasisBijdrage> findByWerkgeversCategorieWerknemersKengetalLooncodeWerkemersKengetalBijdrage(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, DmfapplWnkengetal werknemersKengetalBijdrage) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("werkgeversCategorieCtId", Criterium.EQ(werkgeversCategorie.getId()));
        cb.and("werknemersKengetalCtId", Criterium.EQ(werknemersKengetal.getId()));
        cb.and("werknemersKengetalBijdrageCtId", Criterium.EQ(werknemersKengetalBijdrage.getId()));
        return dmfapplBasisBijdrageService.findByCriteria(cb);
    }

    @Override
    public void clearCache() {
        CachedDmfapplBasisBijdrageService.getBuffer().clear();
    }

    private static class CachedDmfapplBasisBijdrageBuffer {

        private final Map<DmfapplBasisBijdrageKey, List<DmfapplBasisBijdrage>> dmfapplBasisBijdrageBuffer = new HashMap<>();
        private final Map<DmfapplBasisBijdrageKey, Boolean> isOnderworpenAanRszBuffer = new HashMap<>();

        public List<DmfapplBasisBijdrage> get(DmfapplBasisBijdrageKey key) {
            return dmfapplBasisBijdrageBuffer.get(key);
        }

        public void put(DmfapplBasisBijdrageKey key, List<DmfapplBasisBijdrage> lijst) {
            dmfapplBasisBijdrageBuffer.put(key, lijst);
        }

        public Boolean getIsOnderworpen(DmfapplBasisBijdrageKey key) {
            return isOnderworpenAanRszBuffer.get(key);
        }

        public void putIsOnderworpen(DmfapplBasisBijdrageKey key, Boolean value) {
            isOnderworpenAanRszBuffer.put(key, value);
        }

        public void clear() {
            dmfapplBasisBijdrageBuffer.clear();
            isOnderworpenAanRszBuffer.clear();
        }
    }

    private static CachedDmfapplBasisBijdrageBuffer getBuffer() {
        CachedDmfapplBasisBijdrageBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedDmfapplBasisBijdrageBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    @RequiredArgsConstructor
    private static class DmfapplBasisBijdrageKey {

        private final MethodKey methodKey;
        private final int werkgeversCategorie;
        private final int werknemersKengetal;
        private final int werknemersKengetalBijdrage;
        private final int loonkode;
        private final LocalDate datum;

        enum MethodKey {
            STANDARD, ONDERWORPEN_RSZ, FIETSLEASE_FACTOR, STANDARD_GEWOON_LOON
        }

        static DmfapplBasisBijdrageKey getStandardKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, int loonkode) {
            return new DmfapplBasisBijdrageKey(MethodKey.STANDARD, werkgeversCategorie.getCode(), werknemersKengetal.getCode(), 0, loonkode, null);
        }

        static DmfapplBasisBijdrageKey getStandardKey(
                WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, DmfapplWnkengetal werknemersKengetalBijdrage) {
            return new DmfapplBasisBijdrageKey(MethodKey.STANDARD, werkgeversCategorie.getCode(), werknemersKengetal.getCode(), werknemersKengetalBijdrage.getCode(), 0,
                    null);
        }

        static DmfapplBasisBijdrageKey getOnderworpenAanRSZKey(
                WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, int loonkode, LocalDate datum) {
            return new DmfapplBasisBijdrageKey(MethodKey.ONDERWORPEN_RSZ, werkgeversCategorie.getCode(), werknemersKengetal.getCode(), 0, loonkode, datum);
        }

        static DmfapplBasisBijdrageKey getFietsleaseFaktorKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, LocalDate datum) {
            return new DmfapplBasisBijdrageKey(MethodKey.FIETSLEASE_FACTOR, werkgeversCategorie.getCode(), werknemersKengetal.getCode(), 0, 1, datum);
        }

        static DmfapplBasisBijdrageKey getStandardGewoonLoonKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, LocalDate datum) {
            return new DmfapplBasisBijdrageKey(MethodKey.STANDARD_GEWOON_LOON, werkgeversCategorie.getCode(), werknemersKengetal.getCode(), 0, 1, datum);
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<DmfapplBasisBijdrage> findAll() {
        return dmfapplBasisBijdrageService.findAll();
    }

    @Override
    public DmfapplBasisBijdrage create(DmfapplBasisBijdrage constant) {
        return dmfapplBasisBijdrageService.create(constant);
    }

    @Override
    public void update(DmfapplBasisBijdrage constant) {
        dmfapplBasisBijdrageService.update(constant);
    }

    @Override
    public void delete(DmfapplBasisBijdrage constant) {
        dmfapplBasisBijdrageService.delete(constant);
    }

    @Override
    public DmfapplBasisBijdrage getById(Integer id) {
        return dmfapplBasisBijdrageService.getById(id);
    }

    @Override
    public DmfapplBasisBijdrage getById(Integer id, String fetchFields) {
        return dmfapplBasisBijdrageService.getById(id, fetchFields);
    }

    @Override
    public DmfapplBasisBijdrage getByCriteria(CriteriaBuilder cb) {
        return dmfapplBasisBijdrageService.getByCriteria(cb);
    }


    @Override
    public List<DmfapplBasisBijdrage> findAll(String fetchFields) {
        return dmfapplBasisBijdrageService.findAll(fetchFields);
    }

