    public List<DmfapplBasisBijdrage> findByCriteria(CriteriaBuilder cb) {
        return dmfapplBasisBijdrageService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return dmfapplBasisBijdrageService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, DmfapplBasisBijdrage> cacheByCriteria(CriteriaBuilder cb) {
        return dmfapplBasisBijdrageService.cacheByCriteria(cb);
    }

    @Override
    public DmfapplBasisBijdrage getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return dmfapplBasisBijdrageService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<DmfapplBasisBijdrage> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return dmfapplBasisBijdrageService.findByCriteriaTemporalFree(cb);
    }


}
